package com.finance.model; import java.math.BigDecimal; import java.time.LocalDate; public class Transaction { private String id; private String description; private BigDecimal amount; private LocalDate date; public Transaction(String id, String description, BigDecimal amount, LocalDate date) { this.id = id; this.description = description; this.amount = amount; this.date = date; } public String getId() { return id; } }
